package main

import "fmt"

func main() {
    var n int
    fmt.Scan(&n)

    v := make([]int, n)

    for i := 0; i < n; i++ {
        fmt.Scan(&v[i])
    }

    maior := 0
    repetidos := []int{}

    cont := 1

    for i := 1; i < n; i++ {

        if v[i] == v[i-1] {
            cont++
        } else {

            if cont > maior {
                maior = cont
                repetidos = []int{v[i-1]}

            } else if cont == maior {
                repetidos = append(repetidos, v[i-1])
            }

            cont = 1
        }
    }

    // trata o último grupo
    if cont > maior {
        repetidos = []int{v[n-1]}
    } else if cont == maior {
        repetidos = append(repetidos, v[n-1])
    }

    fmt.Print("[ ")
    for _, x := range repetidos {
        fmt.Print(x, " ")
    }
    fmt.Println("]")
}
